import{_ as o,o as r,c as a,ae as n}from"./chunks/framework.C8MNLDzb.js";const d=JSON.parse('{"title":"唐宋典故","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sucai/ji/唐宋.md","filePath":"docs/sucai/ji/唐宋.md"}'),s={name:"docs/sucai/ji/唐宋.md"};function e(g,t,i,h,u,l){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="唐宋典故" tabindex="-1">唐宋典故 <a class="header-anchor" href="#唐宋典故" aria-label="Permalink to &quot;唐宋典故&quot;">​</a></h1><h2 id="阳关折柳" tabindex="-1">阳关折柳 <a class="header-anchor" href="#阳关折柳" aria-label="Permalink to &quot;阳关折柳&quot;">​</a></h2><p><strong>典故：</strong> 古人送客至渭城，有&quot;客舍青青柳色新&quot;之说，折柳枝相赠以示离别。柳与&quot;留&quot;谐音，表示挽留之意。 <strong>出处：</strong> 王维《送元二使安西》&quot;渭城朝雨浥轻尘，客舍青青柳色新&quot; <strong>释义：</strong> 指友人离别时折柳相送的习俗，后泛指离别送行。</p><h2 id="雪中送炭" tabindex="-1">雪中送炭 <a class="header-anchor" href="#雪中送炭" aria-label="Permalink to &quot;雪中送炭&quot;">​</a></h2><p><strong>典故：</strong> 宋太宗时，有一年天气严寒，大雪纷飞。太宗命人给贫困百姓和军属送去银两和木炭，帮助他们渡寒。百姓感谢，称之为&quot;雪中送炭&quot;。 <strong>出处：</strong> 《宋史·太宗本纪》 <strong>释义：</strong> 在别人急需时及时给予帮助。</p><h2 id="雪夜访戴" tabindex="-1">雪夜访戴 <a class="header-anchor" href="#雪夜访戴" aria-label="Permalink to &quot;雪夜访戴&quot;">​</a></h2><p><strong>典故：</strong> 王子猷居住在山阴时，某夜大雪纷飞，他睡醒后打开房门，酌酒赏雪，四望皎然。他忽然想起好友戴逵，便连夜乘船去拜访。经过一夜才到戴逵门前，却又转身返回。别人问他为什么，他说：&quot;我本来是乘着兴致去的，兴致消尽了就回来，何必一定要见到戴逵呢？&quot; <strong>出处：</strong> 《世说新语·任诞》 <strong>释义：</strong> 比喻做事随心所欲，不执着于结果。</p><h2 id="咏絮才高" tabindex="-1">咏絮才高 <a class="header-anchor" href="#咏絮才高" aria-label="Permalink to &quot;咏絮才高&quot;">​</a></h2><p><strong>典故：</strong> 东晋谢安在一个下雪的日子问孩子们：&quot;白雪纷纷何所似？&quot;侄子谢朗说：&quot;撒盐空中差可拟。&quot;侄女谢道韫说：&quot;未若柳絮因风起。&quot;谢安大笑，非常赞赏。 <strong>出处：</strong> 《世说新语·言语》 <strong>释义：</strong> 称赞女子的才华卓绝。</p><h2 id="东床坦腹" tabindex="-1">东床坦腹 <a class="header-anchor" href="#东床坦腹" aria-label="Permalink to &quot;东床坦腹&quot;">​</a></h2><p><strong>典故：</strong> 东晋时，太尉郗鉴派人到王导家选女婿，王导让人去东边厢房看看子弟们。子弟们一个个都庄重地坐着，只有一个人在东床上露着肚子躺着，好像什么都没听见。郗鉴说：&quot;这个人正是我想要的女婿。&quot;一打听，是王羲之。 <strong>出处：</strong> 《世说新语·雅量》 <strong>释义：</strong> 指优秀女婿的代称，也形容豁达不俗的气度。</p><h2 id="春风得意" tabindex="-1">春风得意 <a class="header-anchor" href="#春风得意" aria-label="Permalink to &quot;春风得意&quot;">​</a></h2><p><strong>典故：</strong> 孟郊年轻时隐居山林，生活贫困，直到四十六岁才考中进士，写下《登科后》：&quot;昔日龌龊不足夸，今朝放荡思无涯。春风得意马蹄疾，一日看尽长安花。&quot; <strong>出处：</strong> 孟郊《登科后》 <strong>释义：</strong> 形容人在做事顺利或愿望实现时兴高采烈的样子。</p><h2 id="曲水流觞" tabindex="-1">曲水流觞 <a class="header-anchor" href="#曲水流觞" aria-label="Permalink to &quot;曲水流觞&quot;">​</a></h2><p><strong>典故：</strong> 永和九年（353年），王羲之与友人谢安、孙绰等人在会稽山阴的兰亭修禊，曲水流觞，众诗得三十七首，王羲之作《兰亭集序》。 <strong>出处：</strong> 王羲之《兰亭集序》 <strong>释义：</strong> 古代文人饮酒作诗的雅事，后成为风雅娱乐的代称。</p><h2 id="梦笔生花" tabindex="-1">梦笔生花 <a class="header-anchor" href="#梦笔生花" aria-label="Permalink to &quot;梦笔生花&quot;">​</a></h2><p><strong>典故：</strong> 传说李白少年时梦见笔头上生出花来，从此文思敏捷，下笔成章。 <strong>出处：</strong> 五代·王仁裕《开元天宝遗事·梦笔头生花》 <strong>释义：</strong> 比喻写作能力增强，或才华横溢，文思丰富。</p><h2 id="江郎才尽" tabindex="-1">江郎才尽 <a class="header-anchor" href="#江郎才尽" aria-label="Permalink to &quot;江郎才尽&quot;">​</a></h2><p><strong>典故：</strong> 南朝文学家江淹年少时才华横溢，文章写得好，诗歌精采异常。晚年时有一天宿省，梦见一个叫张协的人对他说：&quot;前以一匹锦相寄，今可见还。&quot;江淹把锦给了那人，从此文思减退，再也写不出好文章了。 <strong>出处：</strong> 《南史·江淹传》 <strong>释义：</strong> 比喻人的文思减退，才能用尽。</p><h2 id="推敲" tabindex="-1">推敲 <a class="header-anchor" href="#推敲" aria-label="Permalink to &quot;推敲&quot;">​</a></h2><p><strong>典故：</strong> 贾岛初次到京城参加科举。一天，他骑着驴子在街上走，想出了两句诗：&quot;鸟宿池边树，僧敲月下门。&quot;一开始想用&quot;推&quot;字，又想用&quot;敲&quot;字，在驴背上反复比较，不知不觉冲撞了韩愈的仪仗队。韩愈问清原因后，说：&quot;用&#39;敲&#39;字好。&quot; <strong>出处：</strong> 《苕溪渔隐丛话·前集》卷十九引《刘宾客嘉话录》 <strong>释义：</strong> 比喻做文章或做事时反复琢磨，精心研究。</p><h2 id="囊萤映雪" tabindex="-1">囊萤映雪 <a class="header-anchor" href="#囊萤映雪" aria-label="Permalink to &quot;囊萤映雪&quot;">​</a></h2><p><strong>典故：</strong> 晋代车胤家贫无油点灯，夏季用白色薄纱口袋装萤火虫借光读书；孙康家贫无油点灯，冬天坐在雪地里，借雪光映照读书。 <strong>出处：</strong> 《晋书·车胤传》《孙康传》 <strong>释义：</strong> 形容在艰难条件下勤奋读书。</p><h2 id="悬梁刺股" tabindex="-1">悬梁刺股 <a class="header-anchor" href="#悬梁刺股" aria-label="Permalink to &quot;悬梁刺股&quot;">​</a></h2><p><strong>典故：</strong> 汉代孙敬好学，读书至深夜，为了不让自己打瞌睡，用绳子把头发绑起来系在房梁上；战国时苏秦游说秦王失败后，回家发奋读书，困倦时用锥子刺自己的大腿。 <strong>出处：</strong> 《太平御览》卷三六三引《汉书》 <strong>释义:</strong> 形容学习意志顽强，刻苦勤奋。</p>',25)])])}const c=o(s,[["render",e]]);export{d as __pageData,c as default};
